#include <bits/stdc++.h>
using namespace std;

const int N=205,INF=0x3f3f3f3f;

int n,m,st,en,ls[N],len,edge[N][3],a[N][N];
map<int,int> id;

int solve(){
    int ans[N][N],base[N][N],tmp[N][N];
    memset(ans,0x3f,sizeof(ans));
    for(int i=1;i<=len;i++){
        ans[i][i]=0;
        for(int j=1;j<=len;j++)
            base[i][j]=a[i][j];
    }
    while(n){
        if(n&1){
            for(int i=1;i<=len;i++)
                for(int j=1;j<=len;j++)
                    tmp[i][j]=ans[i][j],ans[i][j]=INF;
            for(int i=1;i<=len;i++)
                for(int j=1;j<=len;j++)
                    for(int k=1;k<=len;k++)
                        ans[i][j]=min(ans[i][j],tmp[i][k]+base[k][j]);
        }
        for(int i=1;i<=len;i++)
            for(int j=1;j<=len;j++)
                tmp[i][j]=base[i][j],base[i][j]=INF;
        for(int i=1;i<=len;i++)
            for(int j=1;j<=len;j++)
                for(int k=1;k<=len;k++)
                    base[i][j]=min(base[i][j],tmp[i][k]+tmp[k][j]);
        n>>=1;
    }
    return ans[id[st]][id[en]];
}

int main(){
    scanf("%d%d%d%d",&n,&m,&st,&en);
    for(int i=1;i<=m;i++){
        scanf("%d%d%d",&edge[i][2],&edge[i][0],&edge[i][1]);
        ls[2*i-1]=edge[i][0],ls[2*i]=edge[i][1];
    }
    sort(ls+1,ls+2*m+1);
    len=unique(ls+1,ls+2*m+1)-ls-1;
    for(int i=1;i<=len;i++)
        id[ls[i]]=i;
    memset(a,0x3f,sizeof(a));
    for(int i=1;i<=m;i++){
        int u=id[edge[i][0]],v=id[edge[i][1]],w=edge[i][2];
        a[u][v]=a[v][u]=min(a[u][v],w);
    }
    printf("%d",solve());
    return 0;
}
